mapper.select:
SELECT B1.* FROM ( SELECT A1.*, ROW_NUMBER() OVER () AS PAGEINDEX FROM ( SELECT requestMapping.BUSINESS_TYPE_CD AS businessTypeCd, /* 사업구분 */ CASE WHEN deployInfo.DEPLOY_NORMAL_YN = 'Y' THEN ( SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.normalArea' AND lang.LANG_TYPE = #{sessionLang} ) WHEN deployInfo.DEPLOY_SPECIAL_YN = 'Y' THEN ( SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.specialArea' AND lang.LANG_TYPE = #{sessionLang} ) ELSE ( SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.viewing' AND lang.LANG_TYPE = #{sessionLang} ) END AS deployTypeNm, /* 배포유형 */ CASE WHEN deployInfo.DEPLOY_NORMAL_YN = 'Y' THEN 'NORMAL' WHEN deployInfo.DEPLOY_SPECIAL_YN = 'Y' THEN 'SPECIAL' ELSE 'VIEWING' END AS distributeTypeCd, /* 배포유형_CODE */ request.REQUEST_NO AS requestNo, /* 요청번호 */ requestMapping.OBJECT_NO AS objectNo, /* 도면번호 */ requestMapping.OBJECT_NM AS documentNm, /* 도면명 */ fileInfo.ORG_FILE_NM AS fileNm, fileInfo.ORG_FILE_NM AS orgFileNm, fileInfo.FILE_NO AS fileNo, requestMapping.REV_NO AS revNo, /* REV */ request.REQUEST_PURPOSE AS requestPurpose, /* 용도 */ acceptUser.USER_CD AS purchaserUserCd, /* 구매담당자 */ acceptUser.USER_NM AS purchaserUserNm, /* 구매담당자 */ TO_CHAR(TO_DATE(fileInfo.USE_END_YMD, 'YYYYMMDD'), 'YYYY-MM-DD') AS formattedUseEndYmd, /* 유효기간 */ request.INSERT_DT AS requestDt, /* 요청일 */ request.APPROVAL_DT AS approvalDt, /* 승인일 */ requestMapping.STD_GAPP_DT AS stdGappDt, /* 규격화 승인일 */ requestMapping.CHANGE_GAPP_DT AS changeGappDt, /* 기술변경 승인일 */ requestMapping.PRODUCT_CD AS productCd, /* 기종 */ COALESCE(requestMapping.PRODUCT_CD, '') AS productNm, /* 기종 */ requestMapping.PROTECT_YN AS protectYn, /* 방산기술 */ ( SELECT COUNT(*) FROM DOCS_DESTROY_FILE destroyFile WHERE destroyFile.DESTROY_NO = approvalFile.DESTROY_NO::text ) AS fileCount, companyUser.USER_CD AS companyUserCd, companyUser.USER_NM AS companyUserNm, fileInfo.DESTROY_TYPE AS destroyType, /* 폐기구분 */ fileInfo.DESTROY_STATUS_CD AS destroyStatusCd, /* 폐기상태 */ FN_GET_CD_NM('requestPurpose', request.REQUEST_PURPOSE, #{sessionLang}) AS requestPurposeNm, /* 용도명 */ FN_GET_CD_NM('destroyStatusCd', fileInfo.DESTROY_STATUS_CD, #{sessionLang}) AS destroyStatusNm, /* 폐기상태명 */ FN_GET_CD_NM('businessTypeCd', requestMapping.BUSINESS_TYPE_CD, #{sessionLang}) AS businessTypeNm, /* 사업구분명 */ FN_GET_CD_NM('destroyType', fileInfo.DESTROY_TYPE, #{sessionLang}) AS destroyTypeNm, /* 폐기구분명 */ approvalFile.LAST_DESTROY_REQUEST_NO AS lastDestroyRequestNo, fileInfo.OBJECT_ID AS objectId, fileInfo.DOWNLOAD_COUNT AS downloadCount, request.BUSINESS_AREA_CD AS businessAreaCd, FN_GET_CD_NM('businessAreaCd', request.BUSINESS_AREA_CD, #{sessionLang}) AS businessAreaNm, ( SELECT FN_GET_CD_NM('distributeTypeCd', info.DISTRIBUTE_TYPE_CD, 'ko') FROM DOCS_DOCUMENT info WHERE info.OBJECT_ID = requestMapping.OBJECT_ID ) AS distributeFileType, ( SELECT USER_NM FROM DOCS_USER t WHERE t.USER_CD = request.INSERT_USER_CD ) AS requestUserNm, ( SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ACTUAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS deployUserNm /* 배포자 */ FROM DOCS_REQUEST_MAPPING requestMapping INNER JOIN DOCS_REQUEST request ON request.REQUEST_NO = requestMapping.REQUEST_NO INNER JOIN DOCS_REQUEST_DEPLOY deployInfo ON deployInfo.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_USER companyUser ON companyUser.USER_CD = deployInfo.DEPLOY_USER_CD INNER JOIN DOCS_REQUEST_DETAIL requestDetail ON requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' INNER JOIN DOCS_USER acceptUser ON acceptUser.USER_CD = requestDetail.ORIGINAL_USER_CD INNER JOIN DOCS_REQUEST_FILE fileInfo ON request.REQUEST_NO = fileInfo.REQUEST_NO AND requestMapping.OBJECT_ID = fileInfo.OBJECT_ID LEFT JOIN DOCS_APPROVAL_FILE approvalFile ON approvalFile.REQUEST_NO = fileInfo.REQUEST_NO AND approvalFile.OBJECT_ID = fileInfo.OBJECT_ID AND approvalFile.FILE_NO = fileInfo.FILE_NO LEFT JOIN DOCS_DESTROY_REQUEST destroyRequest ON destroyRequest.DESTROY_REQUEST_NO = approvalFile.LAST_DESTROY_REQUEST_NO WHERE request.OBJECT_TYPE = 'DOC' AND request.VENDOR_ACCEPT_YN = 'Y' /* 업체에서 배포접수한 대상만 표시 */ AND request.DEPLOY_COMPANY_CD = #{sessionUser.companyCd, jdbcType=VARCHAR} /* 로그인 한 사용자와 같은 회사의 요청 정보만 표시 */ AND request.REQUEST_TYPE = 'DISTRIBUTION' /* 배포요청정보만 표시 */ AND request.STATUS_CD = 'APPROVAL'
AND request.INSERT_DT BETWEEN TO_DATE(#{requestStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{requestEndDt}, 'YYYY-MM-DD') + INTERVAL '1 day'
AND fileInfo.USE_END_YMD >= TO_CHAR(CURRENT_DATE - (SELECT SYSTEM_CONFIG_VALUE::INTEGER FROM DOCS_SYSTEM_CONFIG t WHERE t.SYSTEM_CONFIG_GROUP = 'SYSTEM_CONFIG' AND t.SYSTEM_CONFIG_CD = 'VALID_TERM'), 'YYYYMMDD') AND fileInfo.USE_END_YMD <= TO_CHAR(CURRENT_DATE, 'YYYYMMDD')
ORDER BY CASE WHEN #{validTermLimitYn} = 'Y' THEN TO_DATE(fileInfo.USE_END_YMD, 'YYYY-MM-DD') ELSE request.INSERT_DT END DESC, request.INSERT_DT DESC, requestNo DESC
ORDER BY ${sortColumn} ${order}
) A1 WHERE 1 = 1
AND requestNo = #{requestNo}
AND objectNo LIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND documentNm LIKE '%' || #{documentNm} || '%'
AND purchaserUserCd = #{purchaserUserCd}
AND companyUserCd = #{companyUserCd}
AND destroyStatusCd = #{destroyStatusCd}
AND fileInfo.USE_END_YMD < TO_CHAR(CURRENT_DATE, 'YYYY-MM-DD')
AND businessAreaCd = #{businessAreaCd}
) B1
WHERE PAGEINDEX >= #{start}
AND PAGEINDEX <= #{end} ;

SELECT COUNT(*) AS TOTAL_COUNT FROM ( SELECT B1.* FROM ( SELECT A1.* FROM ( SELECT requestMapping.BUSINESS_TYPE_CD AS businessTypeCd /* 사업구분 */ , CASE WHEN deployInfo.DEPLOY_NORMAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.normalArea' AND lang.LANG_TYPE = #{sessionLang}) WHEN deployInfo.DEPLOY_SPECIAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.specialArea' AND lang.LANG_TYPE = #{sessionLang}) ELSE (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.viewing' AND lang.LANG_TYPE = #{sessionLang}) END AS deployTypeNm /* 배포유형 */ , CASE WHEN deployInfo.DEPLOY_NORMAL_YN = 'Y' THEN 'NORMAL' WHEN deployInfo.DEPLOY_SPECIAL_YN = 'Y' THEN 'SPECIAL' ELSE 'VIEWING' END AS distributeTypeCd /* 배포유형_CODE */ , request.REQUEST_NO AS requestNo/* 요청번호 */ , requestMapping.OBJECT_NO AS objectNo/* 도면번호 */ , requestMapping.OBJECT_NM AS documentNm/* 도면명 */ , fileInfo.ORG_FILE_NM AS fileNm , fileInfo.ORG_FILE_NM AS orgFileNm , fileInfo.FILE_NO AS fileNo , requestMapping.REV_NO AS revNo/* REV */ , request.REQUEST_PURPOSE AS requestPurpose/* 용도 */ , acceptUser.USER_CD AS purchaserUserCd/* 구매담당자 */ , acceptUser.USER_NM AS purchaserUserNm/* 구매담당자 */ , TO_CHAR(TO_DATE(fileInfo.USE_END_YMD, 'YYYYMMDD'), 'YYYY-MM-DD') AS useEndYmd/* 유효기간 */ , request.INSERT_DT AS requestDt /* 요청일 */ , request.APPROVAL_DT AS approvalDt/* 승인일 */ , requestMapping.PRODUCT_CD AS productCd/* 기종 */ ,COALESCE(requestMapping.PRODUCT_CD, '') AS productNm /* 기종 */ , requestMapping.PROTECT_YN AS protectYn/* 방산기술 */ , ( SELECT COUNT(*) FROM DOCS_DESTROY_FILE destroyFile WHERE destroyFile.DESTROY_NO = approvalFile.DESTROY_NO::text ) AS fileCount , companyUser.USER_CD AS companyUserCd , companyUser.USER_NM AS companyUserNm , fileInfo.DESTROY_TYPE AS destroyType /* 폐기구분 */ , fileInfo.DESTROY_STATUS_CD AS destroyStatusCd /* 폐기상태 */ , FN_GET_CD_NM('requestPurpose', request.REQUEST_PURPOSE, #{sessionLang}) AS requestPurposeNm /* 폐기상태명*/ , FN_GET_CD_NM('destroyStatusCd', fileInfo.DESTROY_STATUS_CD, #{sessionLang}) AS destroyStatusNm /* 폐기상태명*/ , FN_GET_CD_NM('businessTypeCd', requestMapping.BUSINESS_TYPE_CD, #{sessionLang}) AS businessTypeNm /* 사업구분*/ , FN_GET_CD_NM('destroyType', fileInfo.DESTROY_TYPE, #{sessionLang}) AS destroyTypeNm /* 폐기구분*/ , approvalFile.LAST_DESTROY_REQUEST_NO AS lastDestroyRequestNo , fileInfo.OBJECT_ID AS objectId , request.BUSINESS_AREA_CD AS businessAreaCd , FN_GET_CD_NM('businessAreaCd', request.BUSINESS_AREA_CD, #{sessionLang}) AS businessAreaNm , (SELECT FN_GET_CD_NM('distributeTypeCd', info.DISTRIBUTE_TYPE_CD, 'ko') FROM DOCS_DOCUMENT info WHERE info.OBJECT_ID = requestMapping.OBJECT_ID) AS distributeFileType , (SELECT USER_NM FROM DOCS_USER t WHERE t.USER_CD = request.INSERT_USER_CD) AS requestUserNm , ( SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ACTUAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS deployUserNm /* 배포자 */ FROM DOCS_REQUEST_MAPPING requestMapping INNER JOIN DOCS_REQUEST request ON request.REQUEST_NO = requestMapping.REQUEST_NO INNER JOIN DOCS_REQUEST_DEPLOY deployInfo ON deployInfo.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_USER companyUser ON companyUser.USER_CD = deployInfo.DEPLOY_USER_CD INNER JOIN DOCS_REQUEST_DETAIL requestDetail ON requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' INNER JOIN DOCS_USER acceptUser ON acceptUser.USER_CD = requestDetail.ORIGINAL_USER_CD INNER JOIN DOCS_REQUEST_FILE fileInfo ON request.REQUEST_NO = fileInfo.REQUEST_NO AND requestMapping.OBJECT_ID = fileInfo.OBJECT_ID LEFT JOIN DOCS_APPROVAL_FILE approvalFile ON approvalFile.REQUEST_NO = fileInfo.REQUEST_NO AND approvalFile.OBJECT_ID = fileInfo.OBJECT_ID AND approvalFile.FILE_NO = fileInfo.FILE_NO LEFT JOIN DOCS_DESTROY_REQUEST destroyRequest ON destroyRequest.DESTROY_REQUEST_NO = approvalFile.LAST_DESTROY_REQUEST_NO WHERE request.OBJECT_TYPE = 'DOC' AND request.VENDOR_ACCEPT_YN = 'Y' /* 업체에서 배포접수한 대상만 표시 */ AND request.DEPLOY_COMPANY_CD = #{sessionUser.companyCd, jdbcType=VARCHAR} /* 로그인 한 사용자와 같은 회사의 요청 정보만 표시 */ AND request.REQUEST_TYPE = 'DISTRIBUTION' /* 배포요청정보만 표시 */ AND request.STATUS_CD = 'APPROVAL'
AND request.INSERT_DT BETWEEN TO_DATE(#{requestStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{requestEndDt}, 'YYYY-MM-DD') + INTERVAL '1 day'
AND fileInfo.USE_END_YMD >= TO_CHAR(CURRENT_DATE - (SELECT SYSTEM_CONFIG_VALUE::INTEGER FROM DOCS_SYSTEM_CONFIG t WHERE t.SYSTEM_CONFIG_GROUP='SYSTEM_CONFIG' AND t.SYSTEM_CONFIG_CD='VALID_TERM'), 'YYYYMMDD') AND fileInfo.USE_END_YMD <= TO_CHAR(CURRENT_DATE, 'YYYYMMDD')
) A1 WHERE 1=1
AND requestNo = #{requestNo}
AND objectNo LIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND documentNm LIKE '%' || #{documentNm} || '%'
AND purchaserUserCd = #{purchaserUserCd}
AND destroyStatusCd = #{destroyStatusCd}
AND companyUserCd = #{companyUserCd}
AND businessAreaCd = #{businessAreaCd}
AND useEndYmd < TO_CHAR(CURRENT_DATE, 'YYYY-MM-DD')
) B1 ) C1
